func personBiographyText(biography string) string {
	trimmedBiography := strings.TrimSpace(biography)
	if trimmedBiography == "" {
		return personBiographyFallbackText
	}

	return trimmedBiography
}

func personHeroSubtitle(person models.PersonDetailsPage) string {
	heroParts := []string{}

	if department := strings.TrimSpace(person.KnownForDepartment); department != "" {
		heroParts = append(heroParts, department)
	}

	if lifeSpan := personLifeSpanText(person.Birthday, person.Deathday); lifeSpan != "" {
		heroParts = append(heroParts, lifeSpan)
	}

	if placeOfBirth := strings.TrimSpace(person.PlaceOfBirth); placeOfBirth != "" {
		heroParts = append(heroParts, placeOfBirth)
	}

	if len(heroParts) == 0 {
		return "Person details"
	}

	return strings.Join(heroParts, " • ")
}

func personLifeSpanText(birthday *time.Time, deathday *time.Time) string {
	switch {
	case birthday != nil && deathday != nil:
		return fmt.Sprintf("%d-%d", birthday.Year(), deathday.Year())
	case birthday != nil:
		return fmt.Sprintf("Born %d", birthday.Year())
	case deathday != nil:
		return fmt.Sprintf("Died %d", deathday.Year())
	default:
		return ""
	}
}

func personAgeText(birthday *time.Time, deathday *time.Time) string {
	if birthday == nil {
		return personUnknownDetailValue
	}

	ageEndDate := time.Now()
	ageSuffix := "years old"

	if deathday != nil {
		ageEndDate = *deathday
		ageSuffix = "years"
	}

	if ageEndDate.Before(*birthday) {
		return personUnknownDetailValue
	}

	age := ageInYears(*birthday, ageEndDate)
	if age < 0 {
		return personUnknownDetailValue
	}

	return fmt.Sprintf("%d %s", age, ageSuffix)
}

func ageInYears(start time.Time, end time.Time) int {
	years := end.Year() - start.Year()
	if end.Month() < start.Month() || (end.Month() == start.Month() && end.Day() < start.Day()) {
		years--
	}

	return years
}

func personValueOrFallback(value string) string {
	trimmedValue := strings.TrimSpace(value)
	if trimmedValue == "" {
		return personUnknownDetailValue
	}

	return trimmedValue
}

func personCrewRoleText(credit models.PersonCredit) string {
	if strings.TrimSpace(credit.Department) == "" || strings.EqualFold(credit.Role, credit.Department) {
		return credit.Role
	}

	return fmt.Sprintf("%s (%s)", credit.Role, credit.Department)
}

func personMediaTypeLabel(mediaType string) string {
	trimmedMediaType := strings.TrimSpace(mediaType)
	if trimmedMediaType == "" {
		return "N/A"
	}

	return strings.ToUpper(trimmedMediaType)
}

func personCreditHref(credit models.PersonCredit) string {
	if credit.MediaType != personMovieMediaType {
		return ""
	}

	return "/movie/" + strconv.FormatInt(credit.ID, 10)
}

func personCreditDateText(date *time.Time) string {
	if date == nil {
		return "Date unknown"
	}

	return date.Format("2006")
}

func personLatestWatchDateText(movies []models.PersonWatchedMovie) string {
	if len(movies) == 0 {
		return "N/A"
	}

	latest := movies[0].LastWatchedDate
	for _, movie := range movies[1:] {
		if movie.LastWatchedDate.After(latest) {
			latest = movie.LastWatchedDate
		}
	}

	if latest.IsZero() {
		return "N/A"
	}

	return latest.Format("Jan 2006")
}

func personWatchCountText(count int64) string {
	if count == 1 {
		return "1 watch"
	}

	return fmt.Sprintf("%d watches", count)
}

func personActorRankText(rank *int64) string {
	if rank == nil || *rank <= 0 {
		return "N/A"
	}

	return fmt.Sprintf("#%d", *rank)
}

func personWatchRolesText(roles []models.PersonWatchRole) string {
	if len(roles) == 0 {
		return ""
	}

	var builder strings.Builder
	for i, role := range roles {
		if i > 0 {
			builder.WriteString(" • ")
		}

		builder.WriteString(personWatchRoleText(role))
	}

	return builder.String()
}

func personWatchRoleText(role models.PersonWatchRole) string {
	label := strings.TrimSpace(role.Label)
	if label == "" {
		if role.Kind == models.PersonWatchRoleKindActing {
			return "as actor"
		}

		return "Crew"
	}

	if role.Kind == models.PersonWatchRoleKindActing {
		return "as " + label
	}

	return label
}

func personRandomBackdropPath(actingCredits []models.PersonCredit, crewCredits []models.PersonCredit) string {
	backdropPaths := personBackdropPaths(actingCredits, crewCredits)
	if len(backdropPaths) == 0 {
		return ""
	}

	return backdropPaths[rand.IntN(len(backdropPaths))]
}

func personBackdropPaths(actingCredits []models.PersonCredit, crewCredits []models.PersonCredit) []string {
	totalCredits := len(actingCredits) + len(crewCredits)
	if totalCredits == 0 {
		return []string{}
	}

	backdropPaths := make([]string, 0, totalCredits)
	seenCreditKeys := make(map[string]struct{}, totalCredits)

	appendBackdropPath := func(credit models.PersonCredit) {
		backdropPath := strings.TrimSpace(credit.BackdropPath)
		if backdropPath == "" {
			return
		}

		creditKey := personCreditGroupingKey(credit)
		if _, exists := seenCreditKeys[creditKey]; exists {
			return
		}

		seenCreditKeys[creditKey] = struct{}{}
		backdropPaths = append(backdropPaths, backdropPath)
	}

	for _, credit := range actingCredits {
		appendBackdropPath(credit)
	}

	for _, credit := range crewCredits {
		appendBackdropPath(credit)
	}

	return backdropPaths
}

func personCreditCardClass(isMovieLink bool) string {
	if isMovieLink {
		return "h-full border-1 hover:bg-white/20 transition-colors duration-300"
	}

	return "h-full border-1"
}

func personInitials(name string) string {
	nameParts := strings.Fields(name)
	if len(nameParts) == 0 {
		return "?"
	}

	firstInitial := []rune(nameParts[0])[0]
	initials := strings.ToUpper(string(firstInitial))

	if len(nameParts) > 1 {
		secondInitial := []rune(nameParts[1])[0]
		initials += strings.ToUpper(string(secondInitial))
	}

	return initials
}

